 1→package com.taskflow.config;
 2→
 3→import com.taskflow.security.JwtAuthFilter;
 4→import org.springframework.context.annotation.Bean;
 5→import org.springframework.context.annotation.Configuration;
 6→import org.springframework.security.config.annotation.web.builders.HttpSecurity;
 7→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
 8→import org.springframework.security.config.http.SessionCreationPolicy;
 9→import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
10→import org.springframework.security.crypto.password.PasswordEncoder;
11→import org.springframework.security.web.SecurityFilterChain;
12→import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
13→
14→@Configuration
15→@EnableWebSecurity
16→public class SecurityConfig {
17→
18→    private final JwtAuthFilter jwtAuthFilter;
19→
20→    public SecurityConfig(JwtAuthFilter jwtAuthFilter) {
21→        this.jwtAuthFilter = jwtAuthFilter;
22→    }
23→
24→    @Bean
25→    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
26→        http
27→            .csrf(csrf -> csrf.disable())
28→            .sessionManagement(session ->
29→                session.sessionCreationPolicy(SessionCreationPolicy.STATELESS)
30→            )
31→            .authorizeHttpRequests(auth -> auth
32→                .requestMatchers("/api/auth/**").permitAll()
33→                .requestMatchers("/h2-console/**").permitAll()
34→                .anyRequest().authenticated()
35→            )
36→            .headers(headers ->
37→                headers.frameOptions(frameOptions -> frameOptions.sameOrigin())
38→            )
39→            .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class);
40→
41→        return http.build();
42→    }
43→
44→    @Bean
45→    public PasswordEncoder passwordEncoder() {
46→        return new BCryptPasswordEncoder();
47→    }
48→}
