11→
12→import java.util.Optional;
13→
14→import static org.assertj.core.api.Assertions.assertThat;
15→
16→/**
17→ * Tests for UserRepository custom query methods.
18→ *
19→ * Covers:
20→ * - findByUsername: happy path, not found, case sensitivity
21→ */
22→@DataJpaTest
23→@ActiveProfiles("test")
24→@DisplayName("UserRepository Tests")
25→class UserRepositoryTest {
26→
27→    @Autowired
28→    private UserRepository userRepository;
29→
30→    @Autowired
31→    private TestEntityManager entityManager;
32→
33→    private User savedUser;
34→
35→    @BeforeEach
36→    void setUp() {
37→        User user = new User();
38→        user.setUsername("john_doe");
39→        user.setPassword("hashed_password");
40→        user.setDisplayName("John Doe");
41→        savedUser = entityManager.persistFlushFind(user);
42→    }
43→
44→    @Test
45→    @DisplayName("should find user by username when user exists")
46→    void shouldFindUserByUsernameWhenUserExists() {
47→        Optional<User> found = userRepository.findByUsername("john_doe");
48→
49→        assertThat(found).isPresent();
50→        assertThat(found.get().getUsername()).isEqualTo("john_doe");
51→        assertThat(found.get().getDisplayName()).isEqualTo("John Doe");
52→        assertThat(found.get().getId()).isEqualTo(savedUser.getId());
53→    }
54→
55→    @Test
56→    @DisplayName("should return empty when username does not exist")
57→    void shouldReturnEmptyWhenUsernameDoesNotExist() {
58→        Optional<User> found = userRepository.findByUsername("nonexistent");
59→
60→        assertThat(found).isEmpty();
61→    }
62→
63→    @Test
64→    @DisplayName("should return empty when username is null")
65→    void shouldReturnEmptyWhenUsernameIsNull() {
66→        Optional<User> found = userRepository.findByUsername(null);
67→
68→        assertThat(found).isEmpty();
69→    }
70→
71→    @Test
72→    @DisplayName("should find correct user among multiple users")
73→    void shouldFindCorrectUserAmongMultipleUsers() {
74→        User user2 = new User();
75→        user2.setUsername("jane_doe");
76→        user2.setPassword("another_hash");
77→        user2.setDisplayName("Jane Doe");
78→        entityManager.persistAndFlush(user2);
79→
80→        Optional<User> found = userRepository.findByUsername("jane_doe");
81→
82→        assertThat(found).isPresent();
83→        assertThat(found.get().getUsername()).isEqualTo("jane_doe");
84→        assertThat(found.get().getDisplayName()).isEqualTo("Jane Doe");
85→    }
86→}
