194→
195→    // ── Contract: DTO field types ──────────────────────────────────────
196→
197→    @Test
198→    @DisplayName("Contract: CreateTaskRequest has title, description, priority fields")
199→    void contractFieldsExist() throws NoSuchMethodException {
200→        assertEquals(String.class, CreateTaskRequest.class.getMethod("getTitle").getReturnType());
201→        assertEquals(String.class, CreateTaskRequest.class.getMethod("getDescription").getReturnType());
