import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Full integration tests for AuthController (M1 Auth API).
 *
 * Covers all 14 acceptance criteria from M1-auth.md:
 * - AC1:  POST /api/auth/register with valid data -> 201
 * - AC2:  POST /api/auth/register with duplicate username -> 409
 * - AC3:  Password stored as bcrypt hash, not plaintext
 * - AC4:  POST /api/auth/login with correct credentials -> 200 + token
 * - AC5:  POST /api/auth/login with wrong password -> 401
 * - AC6:  POST /api/auth/login with non-existent username -> 401
 * - AC7:  GET /api/auth/me with valid token -> 200
 * - AC8:  GET /api/auth/me without Authorization header -> 401
 * - AC9:  GET /api/auth/me with expired token -> 401
 * - AC10: GET /api/auth/me with malformed token -> 401
 * - AC11: Register with username <3 or >50 chars -> 400
 * - AC12: Register with password <8 chars -> 400
 * - AC13: Register with empty or >100 char displayName -> 400
 * - AC14: Register with non-alphanumeric username -> 400
 *
 * Uses @SpringBootTest + @AutoConfigureMockMvc for full end-to-end testing.
 */
@SpringBootTest
@AutoConfigureMockMvc
@ActiveProfiles("test")
@Transactional
@DisplayName("AuthController Integration Tests")
class AuthControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private PasswordEncoder passwordEncoder;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    @Value("${app.jwt.secret}")
    private String jwtSecret;

    private static final String REGISTER_URL = "/api/auth/register";
    private static final String LOGIN_URL = "/api/auth/login";
    private static final String ME_URL = "/api/auth/me";

    private String registerJson(String username, String password, String displayName) {
        return String.format(
                "{\"username\":\"%s\",\"password\":\"%s\",\"displayName\":\"%s\"}",
                username, password, displayName
        );
    }

    private String loginJson(String username, String password) {
        return String.format(
                "{\"username\":\"%s\",\"password\":\"%s\"}",
                username, password
        );
    }

    /**
     * Helper: register a user and return the MvcResult.
     */
    private MvcResult registerUser(String username, String password, String displayName) throws Exception {
        return mockMvc.perform(post(REGISTER_URL)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(registerJson(username, password, displayName)))
                .andReturn();
    }

    /**
     * Helper: register a user, then login, and return the JWT token.
     */
    private String registerAndLogin(String username, String password, String displayName) throws Exception {
        registerUser(username, password, displayName);

        MvcResult loginResult = mockMvc.perform(post(LOGIN_URL)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(loginJson(username, password)))
                .andReturn();

        JsonNode loginBody = objectMapper.readTree(loginResult.getResponse().getContentAsString());
        return loginBody.get("token").asText();
    }

    // ── AC1: Register with valid data -> 201 ─────────────────────────────

    @Nested
    @DisplayName("AC1: POST /api/auth/register with valid data")
    class RegisterValidData {

        @Test
        @DisplayName("should return 201 Created with id, username, displayName")
        void shouldReturn201WithUserResponse() throws Exception {
