    // ── AC3: Password stored as bcrypt hash ──────────────────────────────

    @Nested
    @DisplayName("AC3: Password stored as bcrypt hash")
    class PasswordBcryptHash {

        @Test
        @DisplayName("should store password as bcrypt hash, not plaintext")
        void shouldStoreBcryptHash() throws Exception {
            String rawPassword = "mySecretPassword123";

            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("bcryptuser", rawPassword, "Bcrypt User")))
                    .andExpect(status().isCreated());

            Optional<User> user = userRepository.findByUsername("bcryptuser");
            assertThat(user).isPresent();

            String storedPassword = user.get().getPassword();

            // Must not be plaintext
            assertThat(storedPassword).isNotEqualTo(rawPassword);

            // Must be a valid bcrypt hash (starts with $2a$, $2b$, or $2y$)
            assertThat(storedPassword).matches("^\\$2[aby]?\\$\\d{1,2}\\$.*");

            // Must verify against original password using bcrypt
            assertThat(passwordEncoder.matches(rawPassword, storedPassword)).isTrue();
        }

        @Test
        @DisplayName("should not verify against a different password")
        void shouldNotVerifyDifferentPassword() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("bcryptuser2", "correctPassword1", "Bcrypt User 2")))
                    .andExpect(status().isCreated());

            Optional<User> user = userRepository.findByUsername("bcryptuser2");
            assertThat(user).isPresent();

            assertThat(passwordEncoder.matches("wrongPassword1", user.get().getPassword())).isFalse();
        }
    }

    // ── AC4: Login with correct credentials -> 200 + token ───────────────

    @Nested
    @DisplayName("AC4: POST /api/auth/login with correct credentials")
    class LoginCorrectCredentials {

        @Test
        @DisplayName("should return 200 with token and expiresIn")
        void shouldReturn200WithTokenAndExpiresIn() throws Exception {
            // Register user first
            registerUser("loginuser", "password123", "Login User");

            // Login
            mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("loginuser", "password123")))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.token").isNotEmpty())
                    .andExpect(jsonPath("$.expiresIn").isNumber());
        }

        @Test
        @DisplayName("should return a valid JWT token that can be verified")
        void shouldReturnValidJwtToken() throws Exception {
            registerUser("jwtverify", "password123", "JWT Verify User");

            MvcResult result = mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("jwtverify", "password123")))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode body = objectMapper.readTree(result.getResponse().getContentAsString());
            String token = body.get("token").asText();

            assertThat(token).isNotBlank();
            assertThat(jwtTokenProvider.validateToken(token)).isTrue();
        }

        @Test
        @DisplayName("should return expiresIn as 86400 (24 hours in seconds)")
        void shouldReturnExpiresIn86400() throws Exception {
            registerUser("expiryuser", "password123", "Expiry User");

            mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("expiryuser", "password123")))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.expiresIn").value(86400));
        }
    }

