    // ── AC9: GET /api/auth/me with expired token -> 401 ──────────────────

    @Nested
    @DisplayName("AC9: GET /api/auth/me with expired token")
    class GetMeWithExpiredToken {

        @Test
        @DisplayName("should return 401 when token is expired")
        void shouldReturn401WithExpiredToken() throws Exception {
            // Register a user to get a valid user ID
            registerUser("expireduser", "password123", "Expired User");
            Optional<User> user = userRepository.findByUsername("expireduser");
            assertThat(user).isPresent();

            // Build an expired token manually
            SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes(StandardCharsets.UTF_8));
            String expiredToken = Jwts.builder()
                    .subject(String.valueOf(user.get().getId()))
                    .issuedAt(new Date(System.currentTimeMillis() - 200_000))
                    .expiration(new Date(System.currentTimeMillis() - 100_000)) // expired 100s ago
                    .signWith(key)
                    .compact();

            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer " + expiredToken))
                    .andExpect(status().isUnauthorized());
        }
    }

