    // ── End-to-end flow tests ────────────────────────────────────────────

    @Nested
    @DisplayName("End-to-end auth flow")
    class EndToEndFlow {

        @Test
        @DisplayName("should complete full register -> login -> me flow successfully")
        void shouldCompleteFullAuthFlow() throws Exception {
            // Step 1: Register
            MvcResult registerResult = mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("flowuser", "password123", "Flow User")))
                    .andExpect(status().isCreated())
                    .andReturn();

            JsonNode registerBody = objectMapper.readTree(registerResult.getResponse().getContentAsString());
            long userId = registerBody.get("id").asLong();
            assertThat(userId).isGreaterThan(0);

            // Step 2: Login
            MvcResult loginResult = mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("flowuser", "password123")))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode loginBody = objectMapper.readTree(loginResult.getResponse().getContentAsString());
            String token = loginBody.get("token").asText();
            long expiresIn = loginBody.get("expiresIn").asLong();
            assertThat(token).isNotBlank();
            assertThat(expiresIn).isPositive();

            // Step 3: Get current user with token
            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.id").value(userId))
                    .andExpect(jsonPath("$.username").value("flowuser"))
                    .andExpect(jsonPath("$.displayName").value("Flow User"));
        }
    }
}

package com.taskflow.service;

import com.taskflow.dto.LoginRequest;
import com.taskflow.dto.LoginResponse;
import com.taskflow.dto.RegisterRequest;
import com.taskflow.dto.UserResponse;
import com.taskflow.entity.User;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.security.crypto.password.PasswordEncoder;

import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

/**
 * Unit tests for AuthService.
 *
 * Tests the business logic for:
 * - register: validates uniqueness, encodes password with bcrypt, saves user, returns UserResponse
 * - login: verifies credentials, generates JWT, returns LoginResponse
 * - getCurrentUser: retrieves user by ID, returns UserResponse
 *
 * Uses Mockito to mock dependencies (UserRepository, PasswordEncoder, JwtTokenProvider).
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("AuthService Unit Tests")
class AuthServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private PasswordEncoder passwordEncoder;

    @Mock
    private JwtTokenProvider jwtTokenProvider;

    @InjectMocks
    private AuthService authService;

    private RegisterRequest validRegisterRequest;
    private LoginRequest validLoginRequest;
    private User savedUser;

    @BeforeEach
    void setUp() {
        validRegisterRequest = new RegisterRequest();
        validRegisterRequest.setUsername("testuser");
        validRegisterRequest.setPassword("password123");
        validRegisterRequest.setDisplayName("Test User");

        validLoginRequest = new LoginRequest();
        validLoginRequest.setUsername("testuser");
        validLoginRequest.setPassword("password123");

        savedUser = new User();
        savedUser.setId(1L);
        savedUser.setUsername("testuser");
        savedUser.setPassword("$2a$10$hashedPasswordValue");
        savedUser.setDisplayName("Test User");
    }

    // ── register ─────────────────────────────────────────────────────────

    @Nested
    @DisplayName("register()")
    class Register {

        @Test
        @DisplayName("should encode password with bcrypt before saving")
        void shouldEncodePasswordBeforeSaving() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
            when(passwordEncoder.encode("password123")).thenReturn("$2a$10$encodedHash");
            when(userRepository.save(any(User.class))).thenAnswer(inv -> {
                User user = inv.getArgument(0);
                user.setId(1L);
                return user;
            });

            authService.register(validRegisterRequest);

            ArgumentCaptor<User> userCaptor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(userCaptor.capture());
            assertThat(userCaptor.getValue().getPassword()).isEqualTo("$2a$10$encodedHash");
            verify(passwordEncoder).encode("password123");
        }

        @Test
        @DisplayName("should return UserResponse with id, username, displayName")
        void shouldReturnUserResponse() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
            when(passwordEncoder.encode(anyString())).thenReturn("$2a$10$hashed");
            when(userRepository.save(any(User.class))).thenAnswer(inv -> {
                User user = inv.getArgument(0);
                user.setId(42L);
                return user;
            });

            UserResponse response = authService.register(validRegisterRequest);

            assertThat(response).isNotNull();
            assertThat(response.getId()).isEqualTo(42L);
            assertThat(response.getUsername()).isEqualTo("testuser");
            assertThat(response.getDisplayName()).isEqualTo("Test User");
        }

        @Test
        @DisplayName("should throw exception when username already exists")
        void shouldThrowWhenUsernameExists() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));

            assertThatThrownBy(() -> authService.register(validRegisterRequest))
                    .isInstanceOf(RuntimeException.class);

            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should save user with correct username and displayName")
        void shouldSaveUserWithCorrectFields() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
            when(passwordEncoder.encode(anyString())).thenReturn("$2a$10$hashed");
            when(userRepository.save(any(User.class))).thenAnswer(inv -> {
                User user = inv.getArgument(0);
                user.setId(1L);
                return user;
            });

            authService.register(validRegisterRequest);

            ArgumentCaptor<User> userCaptor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(userCaptor.capture());
            User captured = userCaptor.getValue();
            assertThat(captured.getUsername()).isEqualTo("testuser");
            assertThat(captured.getDisplayName()).isEqualTo("Test User");
        }
    }

    // ── login ────────────────────────────────────────────────────────────

    @Nested
    @DisplayName("login()")
    class Login {

        @Test
        @DisplayName("should return LoginResponse with token and expiresIn on success")
        void shouldReturnLoginResponseOnSuccess() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
            when(passwordEncoder.matches("password123", "$2a$10$hashedPasswordValue")).thenReturn(true);
            when(jwtTokenProvider.generateToken(1L)).thenReturn("jwt.token.here");

            LoginResponse response = authService.login(validLoginRequest);

            assertThat(response).isNotNull();
            assertThat(response.getToken()).isEqualTo("jwt.token.here");
            assertThat(response.getExpiresIn()).isPositive();
        }

        @Test
        @DisplayName("should throw exception when username does not exist")
        void shouldThrowWhenUsernameNotFound() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());

            assertThatThrownBy(() -> authService.login(validLoginRequest))
                    .isInstanceOf(RuntimeException.class);
        }

        @Test
        @DisplayName("should throw exception when password is wrong")
        void shouldThrowWhenPasswordIsWrong() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
            when(passwordEncoder.matches("password123", "$2a$10$hashedPasswordValue")).thenReturn(false);

            assertThatThrownBy(() -> authService.login(validLoginRequest))
                    .isInstanceOf(RuntimeException.class);

            verify(jwtTokenProvider, never()).generateToken(any());
        }

        @Test
        @DisplayName("should generate token using the user's ID")
        void shouldGenerateTokenWithUserId() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
            when(passwordEncoder.matches(anyString(), anyString())).thenReturn(true);
            when(jwtTokenProvider.generateToken(1L)).thenReturn("token");

            authService.login(validLoginRequest);

            verify(jwtTokenProvider).generateToken(1L);
        }
    }

    // ── getCurrentUser ───────────────────────────────────────────────────

    @Nested
    @DisplayName("getCurrentUser()")
    class GetCurrentUser {

        @Test
        @DisplayName("should return UserResponse when user exists")
        void shouldReturnUserResponseWhenUserExists() {
            when(userRepository.findById(1L)).thenReturn(Optional.of(savedUser));

            UserResponse response = authService.getCurrentUser(1L);

            assertThat(response).isNotNull();
            assertThat(response.getId()).isEqualTo(1L);
            assertThat(response.getUsername()).isEqualTo("testuser");
            assertThat(response.getDisplayName()).isEqualTo("Test User");
        }

        @Test
        @DisplayName("should throw exception when user not found by ID")
        void shouldThrowWhenUserNotFoundById() {
            when(userRepository.findById(999L)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> authService.getCurrentUser(999L))
                    .isInstanceOf(RuntimeException.class);
        }
    }

    // ── Contract: method signatures ──────────────────────────────────────

    @Test
    @DisplayName("Contract: AuthService has register, login, getCurrentUser methods")
    void contractMethodsExist() throws NoSuchMethodException {
        assertThat(AuthService.class.getMethod("register", RegisterRequest.class)
                .getReturnType()).isEqualTo(UserResponse.class);
        assertThat(AuthService.class.getMethod("login", LoginRequest.class)
                .getReturnType()).isEqualTo(LoginResponse.class);
        assertThat(AuthService.class.getMethod("getCurrentUser", Long.class)
                .getReturnType()).isEqualTo(UserResponse.class);
    }
}

package com.taskflow.dto;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Validation tests for RegisterRequest DTO.
 * Uses Jakarta Validation directly (no Spring context needed).
 *
 * Validates:
 * - username: 3-50 chars, pattern ^[a-zA-Z0-9_]+$ (AC11, AC14)
 * - password: min 8 chars (AC12)
 * - displayName: 1-100 chars (AC13)
 */
@DisplayName("RegisterRequest Validation Tests")
class RegisterRequestValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setUp() {
        try (ValidatorFactory factory = Validation.buildDefaultValidatorFactory()) {
            validator = factory.getValidator();
        }
    }

    private RegisterRequest validRequest() {
        RegisterRequest request = new RegisterRequest();
        request.setUsername("valid_user");
        request.setPassword("password123");
        request.setDisplayName("Valid User");
        return request;
    }

    // ── Username validation ──────────────────────────────────────────────

    @Nested
    @DisplayName("Username validation")
    class UsernameValidation {

        @Test
        @DisplayName("Valid username (alphanumeric + underscore, 3-50 chars) passes")
        void validUsernamePasses() {
            RegisterRequest request = validRequest();
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username at minimum boundary (3 chars) passes")
        void usernameMinBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("abc");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username at maximum boundary (50 chars) passes")
        void usernameMaxBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("a".repeat(50));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username below minimum (2 chars) fails")
        void usernameBelowMinFails() {
            RegisterRequest request = validRequest();
            request.setUsername("ab");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username above maximum (51 chars) fails")
        void usernameAboveMaxFails() {
            RegisterRequest request = validRequest();
            request.setUsername("a".repeat(51));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Null username fails")
        void nullUsernameFails() {
            RegisterRequest request = validRequest();
            request.setUsername(null);
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty username fails")
        void emptyUsernameFails() {
            RegisterRequest request = validRequest();
            request.setUsername("");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with spaces fails")
        void usernameWithSpacesFails() {
            RegisterRequest request = validRequest();
            request.setUsername("has space");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with special characters fails")
        void usernameWithSpecialCharsFails() {
            RegisterRequest request = validRequest();
            request.setUsername("user@name!");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with hyphen fails")
        void usernameWithHyphenFails() {
            RegisterRequest request = validRequest();
            request.setUsername("user-name");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with digits only passes")
        void usernameWithDigitsOnlyPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("12345");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username with underscores passes")
        void usernameWithUnderscoresPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("user_name_123");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ── Password validation ──────────────────────────────────────────────

    @Nested
    @DisplayName("Password validation")
    class PasswordValidation {

        @Test
        @DisplayName("Password at minimum boundary (8 chars) passes")
        void passwordMinBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setPassword("12345678");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Password below minimum (7 chars) fails")
        void passwordBelowMinFails() {
            RegisterRequest request = validRequest();
            request.setPassword("1234567");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty password fails")
        void emptyPasswordFails() {
            RegisterRequest request = validRequest();
            request.setPassword("");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Null password fails")
        void nullPasswordFails() {
            RegisterRequest request = validRequest();
            request.setPassword(null);
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Long password (100+ chars) passes")
        void longPasswordPasses() {
            RegisterRequest request = validRequest();
            request.setPassword("a".repeat(200));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ── DisplayName validation ───────────────────────────────────────────

    @Nested
    @DisplayName("DisplayName validation")
    class DisplayNameValidation {

        @Test
        @DisplayName("DisplayName at minimum boundary (1 char) passes")
        void displayNameMinBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setDisplayName("A");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("DisplayName at maximum boundary (100 chars) passes")
        void displayNameMaxBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setDisplayName("D".repeat(100));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("DisplayName above maximum (101 chars) fails")
        void displayNameAboveMaxFails() {
            RegisterRequest request = validRequest();
            request.setDisplayName("D".repeat(101));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty displayName fails")
        void emptyDisplayNameFails() {
            RegisterRequest request = validRequest();
            request.setDisplayName("");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Null displayName fails")
        void nullDisplayNameFails() {
            RegisterRequest request = validRequest();
            request.setDisplayName(null);
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("DisplayName with unicode characters passes")
        void displayNameWithUnicodePasses() {
            RegisterRequest request = validRequest();
            request.setDisplayName("Test User Name");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ── Contract: field types ────────────────────────────────────────────

    @Test
    @DisplayName("Contract: RegisterRequest has username, password, displayName getters/setters")
    void contractFieldsExist() throws NoSuchMethodException {
        assertThat(RegisterRequest.class.getMethod("getUsername").getReturnType()).isEqualTo(String.class);
        assertThat(RegisterRequest.class.getMethod("getPassword").getReturnType()).isEqualTo(String.class);
        assertThat(RegisterRequest.class.getMethod("getDisplayName").getReturnType()).isEqualTo(String.class);
        assertThat(RegisterRequest.class.getMethod("setUsername", String.class)).isNotNull();
        assertThat(RegisterRequest.class.getMethod("setPassword", String.class)).isNotNull();
        assertThat(RegisterRequest.class.getMethod("setDisplayName", String.class)).isNotNull();
    }
}

